def _tx_dict(**overrides) -> dict:
    base = dict(
        id=generate_transaction_id(date(2025, 10, 5), "RAPPI", 45000.0, "bogota"),
        date=date(2025, 10, 5),
        original_description="RAPPI*DELIVERY",
        clean_merchant="Rappi",
        amount_original=45_000.0,
        currency_original="COP",
        amount_cop=45_000.0,
        fx_rate=1.0,
        transaction_type="debit",
        category_id=None,
        category_source="none",
        source_bank="bogota",
        source_file="test.pdf",
        account_number=None,
        is_recurring=0,
        notes=None,
    )
    base.update(overrides)
    return base


def _seed_category(db, cat_id=1, name="food", name_es="Comida"):
    db.execute(
        "INSERT OR IGNORE INTO categories (id, name, name_es) VALUES (?,?,?)",
        (cat_id, name, name_es),
    )
    db.commit()


