class TestUpsertTransaction:
    def test_inserts_new_transaction(self, db):
        tx = _tx_dict()
        inserted = upsert_transaction(tx, conn=db)
        assert inserted is True

    def test_skips_duplicate_id(self, db):
        tx = _tx_dict()
        upsert_transaction(tx, conn=db)
        inserted_again = upsert_transaction(tx, conn=db)
        assert inserted_again is False

    def test_inserted_row_retrievable(self, db):
        tx = _tx_dict()
        upsert_transaction(tx, conn=db)
        rows = db.execute("SELECT * FROM transactions WHERE id=?", (tx["id"],)).fetchall()
        assert len(rows) == 1

    def test_amount_cop_stored_correctly(self, db):
        tx = _tx_dict(amount_cop=99_999.0)
        upsert_transaction(tx, conn=db)
        row = db.execute("SELECT amount_cop FROM transactions WHERE id=?", (tx["id"],)).fetchone()
        assert row["amount_cop"] == pytest.approx(99_999.0)

    def test_date_stored_as_string_or_date(self, db):
        tx = _tx_dict()
        upsert_transaction(tx, conn=db)
        row = db.execute("SELECT date FROM transactions WHERE id=?", (tx["id"],)).fetchone()
        assert row["date"] is not None

    def test_transaction_type_debit(self, db):
        tx = _tx_dict(transaction_type="debit")
        upsert_transaction(tx, conn=db)
        row = db.execute("SELECT transaction_type FROM transactions WHERE id=?", (tx["id"],)).fetchone()
        assert row["transaction_type"] == "debit"

    def test_transaction_type_credit(self, db):
        tx_id = generate_transaction_id(date(2025, 10, 31), "NOMINA", 5_000_000.0, "bogota")
        tx = _tx_dict(id=tx_id, transaction_type="credit", amount_cop=5_000_000.0)
        upsert_transaction(tx, conn=db)
        row = db.execute("SELECT transaction_type FROM transactions WHERE id=?", (tx["id"],)).fetchone()
        assert row["transaction_type"] == "credit"


