class TestGetTransactions:
    def test_returns_all_when_no_filters(self, populated_db):
        rows = get_transactions(conn=populated_db)
        assert len(rows) == 15  # 15 transactions in populated_db

    def test_filter_by_month(self, populated_db):
        rows = get_transactions(filters={"month": "2025-10"}, conn=populated_db)
        assert len(rows) == 5  # 5 transactions in October

    def test_filter_by_transaction_type_debit(self, populated_db):
        rows = get_transactions(filters={"transaction_type": "debit"}, conn=populated_db)
        assert all(r["transaction_type"] == "debit" for r in rows)
        assert len(rows) == 12  # 4 debits × 3 months

    def test_filter_by_transaction_type_credit(self, populated_db):
        rows = get_transactions(filters={"transaction_type": "credit"}, conn=populated_db)
        assert all(r["transaction_type"] == "credit" for r in rows)
        assert len(rows) == 3  # 1 income × 3 months

    def test_filter_by_source_bank(self, populated_db):
        rows = get_transactions(filters={"source_bank": "bogota"}, conn=populated_db)
        assert all(r["source_bank"] == "bogota" for r in rows)
        assert len(rows) > 0

    def test_filter_by_category_id(self, populated_db):
        rows = get_transactions(filters={"category_id": 3}, conn=populated_db)
        assert all(r["category_id"] == 3 for r in rows)
        # Netflix + Spotify = 2 × 3 months = 6
        assert len(rows) == 6

    def test_filter_by_date_range(self, populated_db):
        rows = get_transactions(
            filters={"date_from": "2025-11-01", "date_to": "2025-11-30"},
            conn=populated_db,
        )
        assert len(rows) == 5

    def test_returns_list_of_dicts(self, populated_db):
        rows = get_transactions(conn=populated_db)
        assert isinstance(rows, list)
        assert all(isinstance(r, dict) for r in rows)

    def test_empty_db_returns_empty_list(self, db):
        rows = get_transactions(conn=db)
        assert rows == []


