class TestUpsertRule:
    def test_creates_new_rule(self, db):
        _seed_category(db, cat_id=1)
        rule_id = upsert_rule(
            pattern="DIDI",
            match_type="contains",
            category_id=1,
            source="user",
            priority=50,
            bank_scope=None,
            created_from_tx=None,
            conn=db,
        )
        assert isinstance(rule_id, int)
        assert rule_id > 0

    def test_rule_retrievable_after_insert(self, db):
        _seed_category(db, cat_id=1)
        upsert_rule("DIDI", "contains", 1, "user", 50, None, None, conn=db)
        rules = get_active_rules(conn=db)
        patterns = [r["pattern"] for r in rules]
        assert "DIDI" in patterns


