class TestFileAlreadyIngested:
    def test_unknown_hash_returns_false(self, db):
        assert file_already_ingested("nonexistent_hash_xyz", conn=db) is False

    def test_logged_hash_returns_true(self, db):
        entry = dict(
            filename="extracto_oct.pdf",
            file_hash="abc123def456",
            bank="bogota",
            format="pdf",
            rows_extracted=10,
            rows_inserted=10,
            rows_skipped=0,
            status="success",
            error_message=None,
        )
        log_ingest(entry, conn=db)
        assert file_already_ingested("abc123def456", conn=db) is True

    def test_failed_ingest_not_counted_as_ingested(self, db):
        entry = dict(
            filename="broken.pdf",
            file_hash="fail_hash_999",
            bank="bogota",
            format="pdf",
            rows_extracted=0,
            rows_inserted=0,
            rows_skipped=0,
            status="failed",
            error_message="parse error",
        )
        log_ingest(entry, conn=db)
        # Failed ingests: depends on impl — either True (logged) or False (only success counts)
        result = file_already_ingested("fail_hash_999", conn=db)
        assert isinstance(result, bool)


