class TestCheckDuplicates:
    def _make_tx(self, tx_id: str, desc: str = "RAPPI") -> Transaction:
        from tools.ingest.normalizer import normalize, _normalize_currency
        from tools.ingest.parsers.base_parser import RawTransaction, BaseParser

        class _P(BaseParser):
            def extract(self, f): return []
            def get_bank_name(self): return "bogota"

        raw = RawTransaction(
            date_raw="2025-10-05",
            description=desc,
            amount_raw="45000",
            currency_raw="COP",
        )
        tx = normalize(raw, bank="bogota", source_file="test.pdf", parser=_P())
        if tx:
            tx.id = tx_id
        return tx

    def test_all_new_when_db_empty(self, db):
        txs = [self._make_tx("id_a", "RAPPI"), self._make_tx("id_b", "NETFLIX")]
        txs = [t for t in txs if t is not None]
        result = check_duplicates(txs, conn=db)
        assert isinstance(result, DedupResult)
        assert len(result.new) == len(txs)
        assert len(result.duplicates) == 0

    def test_existing_id_is_duplicate(self, db):
        # Insert a row directly then check_duplicates detects it
        known_id = "dup_id_known_1"
        upsert_transaction(_tx_dict(id=known_id), conn=db)

        # Build a Transaction object with the same id using _make_tx and override id
        tx = self._make_tx("will_be_overridden")
        if tx is None:
            pytest.skip("normalize returned None")
        tx.id = known_id   # force same ID as what's in DB

        result = check_duplicates([tx], conn=db)
        assert len(result.duplicates) == 1
        assert len(result.new) == 0
